import rclpy
from rclpy.node import Node
from std_msgs.msg import String
from sub_computer.subcommunicator import SubCommunicator

import random # debug

# Gets surface data and publishes it to a ROS2 topic
# Logs the avg rate of incoming messages every 5 seconds

SUB_DATA_PORT = 7000
SUB_IP = '192.168.10.2'

class SurfacePublisher(Node):
    def __init__(self):
        super().__init__('surface_publisher')
        self.get_logger().info('SurfacePublisher node has been started.')   
        self.publisher_ = self.create_publisher(String, 'surface_data', 10)
        self.timer_period = 5  # seconds
        self.timer = self.create_timer(self.timer_period, self.log_messages)
        self.start_data_server()
        self.messages_received = 0

    def start_data_server(self):
        self.data_server = SubCommunicator(host=SUB_IP, port=SUB_DATA_PORT, logger=self.get_logger())
        self.data_server.receive_callback = self.publish_surface_data
        self.data_server.start_server()
    
    def publish_surface_data(self, message):
        if message is not None:
            msg = String()
            msg.data = message
            self.publisher_.publish(msg)
            self.messages_received += 1
            self.get_logger().info(f'Received surface data: "{msg.data}"')

    def log_messages(self):
        self.get_logger().info(f"Avg messages received per second: {self.messages_received/self.timer_period:.2f}")
        self.messages_received = 0

def main(args=None):
    rclpy.init(args=args)
    node = SurfacePublisher()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    finally:
        rclpy.shutdown()


if __name__ == '__main__':
    main()